-- Pas 1: Schimbăm coloana la VARCHAR temporar
ALTER TABLE users MODIFY COLUMN role VARCHAR(32) NOT NULL DEFAULT 'angajat';

-- Pas 2: Convertim valorile vechi la noile roluri
UPDATE users SET role = 'admin' WHERE role IN ('super_admin', 'admin_hr', 'manager');

-- Pas 3: Aplicăm noul enum cu 3 valori
ALTER TABLE users MODIFY COLUMN role ENUM('admin', 'angajat', 'colaborator') NOT NULL DEFAULT 'angajat';

